@dataclass
class DatabaseConfig:
    """Holds database configuration. Never serialize or log this directly."""

    username: str
    password: str
    host: str
    port: int
    database: str
    alias: str  # A safe, human-readable name for metrics

    @property
    def connection_string(self) -> str:
        """Build connection string. Never expose this in metrics/logs."""
        return (
            f"postgresql://{self.username}:{self.password}"
            f"@{self.host}:{self.port}/{self.database}"
        )

    @property
    def safe_identifier(self) -> str:
        """
        Return a non-reversible identifier for this connection.
        Safe to use in metric labels.
        """
        raw = f"{self.username}@{self.host}:{self.port}/{self.database}"
        return hashlib.sha256(raw.encode()).hexdigest()[:12]

    @property
    def safe_host_label(self) -> str:
        """Return host:port without credentials — acceptable for labels."""
        return f"{self.host}:{self.port}"

    def __repr__(self) -> str:
        """Override repr to prevent accidental credential logging."""
        return (
            f"DatabaseConfig(alias={self.alias!r}, "
            f"host={self.host!r}, port={self.port}, "
            f"database={self.database!r}, username=<REDACTED>, "
            f"password=<REDACTED>)"
        )

    def __str__(self) -> str:
        return self.__repr__()


def load_config_from_env() -> list[DatabaseConfig]:
    """
    Load database configurations from environment variables.

    Expected env vars per database (indexed):
        DB_0_ALIAS, DB_0_USERNAME, DB_0_PASSWORD, DB_0_HOST, DB_0_PORT, DB_0_DATABASE
        DB_1_ALIAS, ...

    For production, prefer a secrets manager (Vault, AWS Secrets Manager, etc.)
    """
    configs = []
    index = 0
    while True:
        prefix = f"DB_{index}_"
        alias = os.environ.get(f"{prefix}ALIAS")
        if alias is None:
            break

        username = os.environ.get(f"{prefix}USERNAME")
        password = os.environ.get(f"{prefix}PASSWORD")
        host = os.environ.get(f"{prefix}HOST")
        port_str = os.environ.get(f"{prefix}PORT", "5432")
        database = os.environ.get(f"{prefix}DATABASE")

        if not all([username, password, host, database]):
            logger.warning(
                "Incomplete config for %s (index %d) — skipping.", alias, index
            )
            index += 1
            continue

        configs.append(
            DatabaseConfig(
                username=username,
                password=password,
                host=host,
                port=int(port_str),
                database=database,
                alias=alias,
            )
        )
        logger.info("Loaded config for database alias=%r (index %d)", alias, index)
        index += 1

    if not configs:
        logger.warning(
            "No database configs found. Set DB_0_ALIAS, DB_0_USERNAME, ... env vars."
        )

    return configs


