# ---------------------------------------------------------------------------
# Database health check
# ---------------------------------------------------------------------------

def check_database_health(config: DatabaseConfig) -> tuple[bool, float]:
    """
    Attempt to connect to the database and run a lightweight query.
    Returns (is_healthy, latency_seconds).

    Credentials are used transiently and never stored in metrics.
    """
    start = time.monotonic()
    try:
        import psycopg2

        conn = psycopg2.connect(
            host=config.host,
            port=config.port,
            user=config.username,
            password=config.password,
            dbname=config.database,
            connect_timeout=5,
        )
        try:
            with conn.cursor() as cur:
                cur.execute("SELECT 1")
                cur.fetchone()
        finally:
            conn.close()

        elapsed = time.monotonic() - start
        return True, elapsed

    except ImportError:
        # psycopg2 not installed — fall back to a TCP socket check
        logger.info(
            "psycopg2 not available; falling back to TCP health check for %s",
            config.alias,
        )
        return _tcp_health_check(config, start)

    except Exception as exc:
        elapsed = time.monotonic() - start
        # Log error WITHOUT credentials
        logger.error(
            "Health check failed for alias=%s host=%s db=%s: %s",
            config.alias,
            config.safe_host_label,
            config.database,
            type(exc).__name__,
        )
        return False, elapsed


def _tcp_health_check(
    config: DatabaseConfig, start: float
) -> tuple[bool, float]:
    """Fallback: just check if the TCP port is reachable."""
    import socket

    try:
        sock = socket.create_connection(
            (config.host, config.port), timeout=5
        )
        sock.close()
        elapsed = time.monotonic() - start
        return True, elapsed
    except OSError as exc:
        elapsed = time.monotonic() - start
        logger.error(
            "TCP check failed for alias=%s host=%s: %s",
            config.alias,
            config.safe_host_label,
            type(exc).__name__,
        )
        return False, elapsed


